{
  "learning_outcomes": [
    {
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "topic": "Explores the world of matter, its interactions, and properties at the atomic level",
      "outcomes": [
        "Describes classification of elements in the Periodic Table, and explains how compounds (including carbon compounds) are formed based on the atomic structure (Bohr's model) and properties (valency).",
        "Investigates the nature and properties of chemical substances (distillation, crystallisation, chromatography, centrifugation, types and properties of mixtures, solutions, colloids, and suspensions).",
        "Describes and represents chemical interactions and changes using symbols and chemical equations (acid and base, metal and non-metal, reversible and irreversible)."
      ]
    },
    {
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "topic": "Explores the structure and function of the living world at the cellular level",
      "outcomes": [
        "Explains the role of cellular components (nucleus, mitochondria, endoplasmic reticulum, vacuoles, chloroplast, cell wall), including the semi-permeability of cell membrane in making cell the structural basis of living organisms and functional basis of life processes.",
        "Analyses similarities and differences in the life processes involved in nutrition (photosynthesis in plants; absorption of nutrients in fungi; digestion in animals), transport (transport of water in plants; circulation in animals), exchange of materials (respiration and excretion), and reproduction.",
        "Describes the mechanisms of heredity (in terms of DNA, genes, chromosomes) and variation (as changes in the sequence of DNA)."
      ]
    },
    {
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "topic": "Explores interconnectedness between organisms and their environment",
      "outcomes": [
        "Applies the knowledge of cellular diversity in organisms along with the ecological role organisms play (autotrophic or heterotrophic nutrition) to classify them into five kingdoms.",
        "Illustrates different levels of organisations of living organisms (from molecules to organisms).",
        "Analyses different levels of biological organisation from organisms to ecosystems and biomes along with interactions that take place at each level.",
        "Analyses patterns of inheritance of traits in terms of Mendel's laws and its consequences at a population level (using models and/or simulations).",
        "Analyses evidences of biological evolution demonstrating the consequences of the process of natural selection in terms of changes — in allele frequency in population, structure, and function of organisms."
      ]
    },
    {
      "unit_name": "Unit 3",
      "chapter_name": "Natural Phenomena",
      "topic": "Explores the physical world around them, and understands scientific principles and laws based on observations and analysis",
      "outcomes": [
        "Applies Newton's laws to explain the effect of forces (change in state of motion — displacement and direction, velocity and acceleration, uniform circular motion, acceleration due to gravity) and analyses graphical and mathematical representations of motion in one dimension.",
        "Explains the relationship between mass and weight using universal law of gravitation, and connect it to the laws of motion.",
        "Manipulates the position of object and properties of lenses (focus, centre of curvature) to observe image characteristics and correspondence with a ray diagram, and extends this understanding to a combination of lenses (telescope, microscope).",
        "Manipulates and analyses different characteristics of the circuit (current, voltage, resistance) and mathematises their relationship (Ohm's law), and applies it to everyday usage (electricity bill, short circuit, safety measures).",
        "Defines work in scientific terms, and represents the relationship between potential and kinetic energy (conservation of energy) in mathematical expressions.",
        "Demonstrates the principle of mechanical advantage by constructing simple machines (system of levers and pulleys).",
        "Describes the origin and properties of sound (wavelength, frequency, amplitude) and differences in what we hear as it propagates through different instruments.",
        "Explores interconnected systems and phenomena that support and affect life on Earth (hydrosphere, biosphere, atmosphere, geosphere, cryosphere and their interrelationships, earth processes, hazards, etc.)."
      ]
    },
    {
      "unit_name": "Unit 4",
      "chapter_name": "Effects of Current",
      "topic": "Explores the nature of Science by doing Science",
      "outcomes": [
        "Develops accurate and appropriate models (including geometric, mathematical, graphical) to represent real-life events and phenomena using scientific principles, and use these models to manipulate variables and predict results.",
        "Designs and implements a plan for scientific inquiry (formulates hypotheses, makes predictions, identifies variables, accurately uses scientific instruments, represents data — primary and secondary — in multiple modes, draws inferences based on data, and understanding of scientific concepts, theories, laws and principles, and communicates findings using scientific terminology)."
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "Natural Resources",
      "topic": "Understands and appreciates the contribution of India through history, and the present time to the overall field of Science",
      "outcomes": [
        "Knows and explains the significant contributions of India to all matters (concepts, explanations, methods) that are studied within the curriculum in an integrated manner."
      ]
    },
    {
      "unit_name": "Unit 5",
      "chapter_name": "Natural Resources",
      "topic": "Develops awareness of the most current discoveries, ideas, and frontiers in all areas of scientific knowledge",
      "outcomes": [
        "States concepts that represent the most current understanding of the matter being studied, ranging from mere familiarity to conceptual understanding of the matter as appropriate to the developmental stage of the students.",
        "States questions related to matters in the curriculum for which current scientific understanding is well-recognised."
      ]
    },
    {
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "topic": "Draws linkages between scientific knowledge and knowledge across other curricular areas",
      "outcomes": [
        "Explores how literature and arts have influenced Science.",
        "Examines a case study related to the use of Science in human life from the perspective of Social Sciences and Ethics (for example, Marie Curie, Jenner, treatment of patients with mental illnesses, the story of the atomic bomb, green revolution and GMOs, conservation of biodiversity).",
        "Applies scientific principles to explain phenomena in other subjects (sound pitch, octave, and amplitude in music; use of muscles in dance form and sports)."
      ]
    },
    {
      "unit_name": "Untitled Chapter",
      "chapter_name": "Untitled Chapter",
      "topic": "No specific competencies mapped",
      "outcomes": []
    }
  ]
}
